mapper.select:
SELECT max( CASE userOperation.operation_type WHEN '17' THEN 1 ELSE NULL END ) like_status,
    max( CASE userOperation.operation_type WHEN '18' THEN 1 ELSE NULL END ) tap_status,
    max( CASE userOperation.operation_type WHEN '19' THEN 1 ELSE NULL END ) collect_status,
    max( CASE userOperation.operation_type WHEN '20' THEN 1 ELSE NULL END ) complete_status
FROM t_user_operation_record userOperation


       AND userOperation.user_id =#{userOperationRecord.userId}


        AND userOperation.event_type =#{userOperationRecord.eventType}


        AND userOperation.event_id =#{userOperationRecord.eventId}
